function ok(name, cond) { cond ? (pass++, console.log("PASS:", name)) : (fail++, console.log("FAIL:", name)); }

// 1. Route params single
let app = new App();
app.get("/users/:id", (req) => ({ status: 200, body: req.params }));
let r = app.handle({ method: "GET", path: "/users/42" });
ok("single param matches & params.id=42", r.status === 200 && r.body.id === "42");

// 1b. Multiple params
app = new App();
app.get("/a/:x/b/:y", (req) => ({ status: 200, body: req.params }));
r = app.handle({ method: "GET", path: "/a/1/b/2" });
ok("multi params x=1,y=2", r.status === 200 && r.body.x === "1" && r.body.y === "2");

// 1c. Non-matching length
app = new App();
app.get("/users/:id", (req) => ({ status: 200, body: req.params }));
r = app.handle({ method: "GET", path: "/users/42/extra" });
ok("extra segment -> 404", r.status === 404);

// 2. Middleware runs in order before handler, next() continues
app = new App();
const order = [];
app.use((req, next) => { order.push("m1"); return next(); });
app.use((req, next) => { order.push("m2"); next(); });
app.get("/", (req) => { order.push("h"); return { status: 200, body: "ok" }; });
r = app.handle({ method: "GET", path: "/" });
ok("middleware order m1,m2,h", order.join(",") === "m1,m2,h");
ok("handler return propagates through chain", r.status === 200 && r.body === "ok");

// 2b. Middleware mutates req visible to handler
app = new App();
app.use((req, next) => { req.user = "bob"; return next(); });
app.get("/", (req) => ({ status: 200, body: req.user }));
r = app.handle({ method: "GET", path: "/" });
ok("middleware mutation visible to handler", r.body === "bob");

// 2c. Short-circuit: middleware returns response w/ numeric status, no next -> handler not run
app = new App();
let handlerRan = false;
app.use((req, next) => ({ status: 401, body: "unauthorized" }));
app.use((req, next) => { handlerRan = true; return next(); });
app.get("/", (req) => { handlerRan = true; return { status: 200, body: "ok" }; });
r = app.handle({ method: "GET", path: "/" });
ok("short-circuit returns mw response", r.status === 401 && r.body === "unauthorized");
ok("short-circuit: handler & later mw did NOT run", handlerRan === false);

// 3. Method-aware 404: path matches but method does not
app = new App();
app.get("/x", (req) => ({ status: 200, body: "g" }));
r = app.handle({ method: "POST", path: "/x" });
ok("method mismatch -> 404", r.status === 404 && r.body === "Not Found");
r = app.handle({ method: "GET", path: "/nope" });
ok("path mismatch -> 404", r.status === 404 && r.body === "Not Found");
r = app.handle({ method: "GET", path: "/x" });
ok("method+path match -> handler", r.status === 200 && r.body === "g");

// 4. handler return value is the response (no middleware case)
app = new App();
app.get("/", (req) => ({ status: 200, body: "direct" }));
r = app.handle({ method: "GET", path: "/" });
ok("handler return value is response (no mw)", r.status === 200 && r.body === "direct");

console.log("\n" + pass + " passed, " + fail + " failed");
process.exit(fail ? 1 : 0);
